import { Avatar, Card, CardActionArea, CardContent, CardHeader, CardMedia, Divider, Typography } from '@material-ui/core'
import { makeStyles } from '@material-ui/styles'
import React from 'react'
import { Link } from 'react-router-dom'

const useStyle = makeStyles(theme => {
  return {
    root: {
      '& .MuiCardActionArea-focusHighlight': {
      background: 'none'
    }
    
  },
  avatar: {
    background: '#162276',
    width: theme.spacing(7),
    height: theme.spacing(7),
  },
  media: {
    height: 0,
    paddingTop: '56.25%'
  },
  
  cardLink: {
    textDecoration: 'none',
    color: 'inherit'
  }
}})


export default function ClassroomCards({ subject }) {
  const classes = useStyle()


  return (
    <div>
      <Card className={classes.root}>
      <Link className={classes.cardLink} 
        to={{
          pathname: '/teacherFeed',
          search: `?${subject.title}`
        }} 
        >
        <CardActionArea >
        <CardMedia
        className={classes.media}
        image={subject.imagebg}
      />
      
          <CardHeader

            title={subject.title}
            subheader={subject.section}
          />

          <Divider />
          <CardContent>
            <Typography>
              {subject.body}
            </Typography>
          </CardContent>
        </CardActionArea>
        </Link>
      </Card>
    </div>
  )
}
